// The two ensures-instances `pc1` and `pc2` reference the same `pre_self_`,
// so unfolding `next_get_request_postconditions` (already revealed) pins both
// `post1_self_@` and `post2_self_@` to the same field values of `pre_self_@`
// on every spec-determined component (delegation_map, h, num_delegations,
// constants, received_packet).  We surface each conjunct as an implication
// — Verus must verify each one, but they are tautological once the closed
// `*_postconditions` predicates are revealed — giving z3 matching trigger
// pairs that span both runs.

let pkt = pre_self_@.received_packet.unwrap();

// (a) Shape conjuncts of `next_get_request_postconditions` for each run.
//     These are direct conjuncts of the unfolded predicate, so each one is
//     an `assert(P ==> Q)` where `Q` is literally a conjunct of `P` after
//     revealing the closed spec.
assert(post1_self_.next_get_request_postconditions(pre_self_, r1@) ==>
    cpacket_seq_is_abstractable(r1@));
assert(post2_self_.next_get_request_postconditions(pre_self_, r2@) ==>
    cpacket_seq_is_abstractable(r2@));
assert(post1_self_.next_get_request_postconditions(pre_self_, r1@) ==>
    outbound_packet_seq_is_valid(r1@));
assert(post2_self_.next_get_request_postconditions(pre_self_, r2@) ==>
    outbound_packet_seq_is_valid(r2@));
assert(post1_self_.next_get_request_postconditions(pre_self_, r1@) ==>
    outbound_packet_seq_has_correct_srcs(r1@, pre_self_.constants.me@));
assert(post2_self_.next_get_request_postconditions(pre_self_, r2@) ==>
    outbound_packet_seq_has_correct_srcs(r2@, pre_self_.constants.me@));

// (b) The disjoint-trigger per-index forall: `#[trigger] r1@[i].msg` vs
//     `#[trigger] r2@[i].msg`.  Re-assert each forall under its hypothesis
//     so both runs' instantiations enter the proof context.
assert(post1_self_.next_get_request_postconditions(pre_self_, r1@) ==>
    (forall|i: int| 0 <= i && i < r1@.len() ==>
        (#[trigger] r1@[i].msg) is Message || r1@[i].msg is Ack));
assert(post2_self_.next_get_request_postconditions(pre_self_, r2@) ==>
    (forall|i: int| 0 <= i && i < r2@.len() ==>
        (#[trigger] r2@[i].msg) is Message || r2@[i].msg is Ack));

// (c) The abstract step relation `next_get_request(pre@, post_i@, pkt, out_i)`
//     pinned to the abstractified sequence for each run.  `next_get_request`
//     is `open spec`, so its conjuncts auto-unfold and force the abstract
//     post-state field equalities listed below.
assert(post1_self_.next_get_request_postconditions(pre_self_, r1@) ==>
    next_get_request(pre_self_@, post1_self_@, pkt,
        abstractify_seq_of_cpackets_to_set_of_sht_packets(r1@)));
assert(post2_self_.next_get_request_postconditions(pre_self_, r2@) ==>
    next_get_request(pre_self_@, post2_self_@, pkt,
        abstractify_seq_of_cpackets_to_set_of_sht_packets(r2@)));

// (d) Per-field equalities of post_i@ vs pre_self_@ on every spec-determined
//     AbstractHostState component (i.e. everything except `sd` and
//     `received_requests`, which are tied through the existential witness
//     in `next_get_request_reply`).
assert(post1_self_.next_get_request_postconditions(pre_self_, r1@) ==>
    post1_self_@.delegation_map == pre_self_@.delegation_map);
assert(post2_self_.next_get_request_postconditions(pre_self_, r2@) ==>
    post2_self_@.delegation_map == pre_self_@.delegation_map);
assert(post1_self_.next_get_request_postconditions(pre_self_, r1@) ==>
    post1_self_@.h == pre_self_@.h);
assert(post2_self_.next_get_request_postconditions(pre_self_, r2@) ==>
    post2_self_@.h == pre_self_@.h);
assert(post1_self_.next_get_request_postconditions(pre_self_, r1@) ==>
    post1_self_@.num_delegations == pre_self_@.num_delegations);
assert(post2_self_.next_get_request_postconditions(pre_self_, r2@) ==>
    post2_self_@.num_delegations == pre_self_@.num_delegations);
assert(post1_self_.next_get_request_postconditions(pre_self_, r1@) ==>
    post1_self_@.constants == pre_self_@.constants);
assert(post2_self_.next_get_request_postconditions(pre_self_, r2@) ==>
    post2_self_@.constants == pre_self_@.constants);
assert(post1_self_.next_get_request_postconditions(pre_self_, r1@) ==>
    post1_self_@.received_packet is None);
assert(post2_self_.next_get_request_postconditions(pre_self_, r2@) ==>
    post2_self_@.received_packet is None);

// (e) Cross-run AbstractHostState field equalities, chained through pre_self_@.
//     These are the direct building blocks of `post1_self_@ == post2_self_@`
//     modulo the two remaining fields (sd, received_requests).
assert((post1_self_.next_get_request_postconditions(pre_self_, r1@) &&
        post2_self_.next_get_request_postconditions(pre_self_, r2@)) ==>
    post1_self_@.delegation_map == post2_self_@.delegation_map);
assert((post1_self_.next_get_request_postconditions(pre_self_, r1@) &&
        post2_self_.next_get_request_postconditions(pre_self_, r2@)) ==>
    post1_self_@.h == post2_self_@.h);
assert((post1_self_.next_get_request_postconditions(pre_self_, r1@) &&
        post2_self_.next_get_request_postconditions(pre_self_, r2@)) ==>
    post1_self_@.num_delegations == post2_self_@.num_delegations);
assert((post1_self_.next_get_request_postconditions(pre_self_, r1@) &&
        post2_self_.next_get_request_postconditions(pre_self_, r2@)) ==>
    post1_self_@.constants == post2_self_@.constants);
assert((post1_self_.next_get_request_postconditions(pre_self_, r1@) &&
        post2_self_.next_get_request_postconditions(pre_self_, r2@)) ==>
    post1_self_@.received_packet == post2_self_@.received_packet);

// (f) Bridge the two map-then-to-set abstractions through the LSHT
//     intermediate that `host_state_common_postconditions` provides.  The
//     `=~=` between `abstractify_seq_of_cpackets_to_set_of_sht_packets(seq)`
//     and `extract_packets_from_lsht_packets(abstractify_outbound_packets_to_seq_of_lsht_packets(seq))`
//     becomes a usable rewrite once both forms appear at the same proof point.
assert(post1_self_.next_get_request_postconditions(pre_self_, r1@) ==>
    abstractify_seq_of_cpackets_to_set_of_sht_packets(r1@) =~=
    extract_packets_from_lsht_packets(
        abstractify_outbound_packets_to_seq_of_lsht_packets(r1@)));
assert(post2_self_.next_get_request_postconditions(pre_self_, r2@) ==>
    abstractify_seq_of_cpackets_to_set_of_sht_packets(r2@) =~=
    extract_packets_from_lsht_packets(
        abstractify_outbound_packets_to_seq_of_lsht_packets(r2@)));
